SELECT mc.category AS category, cm.content AS content, up_t.name AS senderName, COUNT(DISTINCT mc.id) AS recipientCount, DATE_FORMAT(mc.created_at, '%Y-%m-%d %H:%i') AS sentAt, MIN(mc.id) AS id FROM message_conversation mc JOIN chat_message cm ON cm.conversation_id = mc.id LEFT JOIN user_profiles up_t ON up_t.user_id = cm.sender_id
mc.category = #{category}
mc.category IN ('공지', '이벤트')
GROUP BY mc.category, cm.content, cm.sender_id, DATE_FORMAT(mc.created_at, '%Y-%m-%d %H:%i') ORDER BY sentAt DESC LIMIT #{size} OFFSET #{offset}

SELECT u.user_id FROM users u LEFT JOIN user_profiles up ON u.user_id = up.user_id WHERE u.role = 'MEMBER' AND u.is_active = 1 AND u.deleted_at IS NULL
AND up.tier = #{tier}
AND up.trainer_id = #{trainerUserId}

SELECT COUNT(u.user_id) FROM users u LEFT JOIN user_profiles up ON u.user_id = up.user_id
WHERE u.role = 'TRAINER' AND u.is_active = 1 AND u.deleted_at IS NULL
WHERE u.role = 'MEMBER' AND u.is_active = 1 AND u.deleted_at IS NULL AND up.tier = #{tier} AND up.trainer_id = #{trainerUserId}
